143: // executeConcurrentQueries executes queries to multiple datasources concurrently and returns the aggregate result.
144: func (s *ServiceImpl) executeConcurrentQueries(ctx context.Context, user identity.Requester, skipDSCache bool, reqDTO dtos.MetricRequest, queriesbyDs map[string][]parsedQuery) (*backend.QueryDataResponse, error) {
145: 	g, ctx := errgroup.WithContext(ctx)
146: 	g.SetLimit(s.concurrentQueryLimit) // prevent too many concurrent requests
147: 	rchan := make(chan splitResponse, len(queriesbyDs))
148: 
149: 	// Create panic recovery function for loop below
150: 	recoveryFn := func(queries []*simplejson.Json) {
151: 		if r := recover(); r != nil {
152: 			var err error
153: 			s.log.Error("query datasource panic", "error", r, "stack", log.Stack(1))
154: 			if theErr, ok := r.(error); ok {
155: 				err = theErr
156: 			} else if theErrString, ok := r.(string); ok {
157: 				err = errors.New(theErrString)
158: 			} else {
159: 				err = fmt.Errorf("unexpected error - %s", s.cfg.UserFacingDefaultError)
160: 			}
161: 			// Due to the panic, there is no valid response for any query for this datasource. Append an error for each one.
162: 			rchan <- buildErrorResponses(err, queries)
163: 		}
164: 	}
165: 
166: 	// Query each datasource concurrently
167: 	for _, queries := range queriesbyDs {
168: 		rawQueries := make([]*simplejson.Json, len(queries))
169: 		for i := 0; i < len(queries); i++ {
170: 			rawQueries[i] = queries[i].rawQuery
171: 		}
172: 		g.Go(func() error {
173: 			subDTO := reqDTO.CloneWithQueries(rawQueries)
174: 			// Handle panics in the datasource qery
175: 			defer recoveryFn(subDTO.Queries)
176: 
177: 			ctxCopy := contexthandler.CopyWithReqContext(ctx)
178: 			subResp, err := s.QueryData(ctxCopy, user, skipDSCache, subDTO)
179: 			if err == nil {
180: 				reqCtx, header := contexthandler.FromContext(ctxCopy), http.Header{}
181: 				if reqCtx != nil {
182: 					header = reqCtx.Resp.Header()
183: 				}
184: 				rchan <- splitResponse{subResp.Responses, header}
185: 			} else {
186: 				// If there was an error, return an error response for each query for this datasource
187: 				rchan <- buildErrorResponses(err, subDTO.Queries)
188: 			}
189: 			return nil
190: 		})
191: 	}
192: 
193: 	if err := g.Wait(); err != nil {
194: 		return nil, err
195: 	}
196: 	close(rchan)
197: 	resp := backend.NewQueryDataResponse()
198: 	reqCtx := contexthandler.FromContext(ctx)
199: 	for result := range rchan {
200: 		for refId, dataResponse := range result.responses {
201: 			resp.Responses[refId] = dataResponse
202: 		}
203: 		if reqCtx != nil {
204: 			for k, v := range result.header {
205: 				for _, val := range v {
206: 					if !slices.Contains(reqCtx.Resp.Header().Values(k), val) {
207: 						reqCtx.Resp.Header().Add(k, val)
208: 					} else {
209: 						s.log.Warn("skipped duplicate response header", "header", k, "value", val)
210: 					}
211: 				}
212: 			}
213: 		}
214: 	}
215: 
216: 	return resp, nil
217: }
