290: // handleQuerySingleDatasource handles one or more queries to a single datasource
291: func (s *ServiceImpl) handleQuerySingleDatasource(ctx context.Context, user identity.Requester, parsedReq *parsedRequest) (*backend.QueryDataResponse, error) {
292: 	queries := parsedReq.getFlattenedQueries()
293: 	ds := queries[0].datasource
294: 	if err := s.dataSourceRequestValidator.Validate(ds.URL, ds.JsonData, nil); err != nil {
295: 		return nil, datasources.ErrDataSourceAccessDenied
296: 	}
297: 
298: 	// ensure that each query passed to this function has the same datasource
299: 	for _, pq := range queries {
300: 		if ds.UID != pq.datasource.UID {
301: 			return nil, fmt.Errorf("all queries must have the same datasource - found %s and %s", ds.UID, pq.datasource.UID)
302: 		}
303: 	}
304: 
305: 	req := &backend.QueryDataRequest{
306: 		Headers: map[string]string{},
307: 		Queries: []backend.DataQuery{},
308: 	}
309: 
310: 	for _, q := range queries {
311: 		req.Queries = append(req.Queries, q.query)
312: 	}
313: 
314: 	qsDsClient, ok, err := s.qsDatasourceClientBuilder.BuildClient(ds.Type, ds.UID)
315: 	if err != nil {
316: 		return nil, err
317: 	}
318: 
319: 	if !ok { // single tenant flow
320: 		pCtx, err := s.pCtxProvider.GetWithDataSource(ctx, ds.Type, user, ds)
321: 		if err != nil {
322: 			return nil, err
323: 		}
324: 		req.PluginContext = pCtx
325: 		return s.pluginClient.QueryData(ctx, req)
326: 	} else { // query-service flow (single or multi tenant)
327: 		// transform request from backend.QueryDataRequest to k8s request
328: 		k8sReq, err := expr.ConvertBackendRequestToDataRequest(req)
329: 		if err != nil {
330: 			return nil, err
331: 		}
332: 		return qsDsClient.QueryData(ctx, *k8sReq)
333: 	}
334: }
