336: func getTimeRange(query *simplejson.Json, globalFrom string, globalTo string) (string, string, error) {
337: 	tr, ok := query.CheckGet("timeRange")
338: 	if !ok { // timeRange json node does not exist, use global from/to
339: 		return globalFrom, globalTo, nil
340: 	}
341: 	from, err := tr.Get("from").String()
342: 	if err != nil {
343: 		return "", "", errors.New("time range: field 'from' is missing or invalid")
344: 	}
345: 	to, err := tr.Get("to").String()
346: 	if err != nil {
347: 		return "", "", errors.New("time range: field 'to' is missing or invalid")
348: 	}
349: 
350: 	return from, to, nil
351: }
