355: func queryToJson(query *simplejson.Json, supportLocalTimeRange bool) ([]byte, error) {
356: 	if !supportLocalTimeRange {
357: 		return query.MarshalJSON()
358: 	}
359: 
360: 	// we need to remove the `timeRange` attribute from the JSON, if it exists there,
361: 	// because it might cause complications with certain data sources.
362: 	_, has := query.CheckGet(timeRangeKey)
363: 	if !has {
364: 		return query.MarshalJSON()
365: 	}
366: 
367: 	qMap, err := query.Map()
368: 	if err != nil {
369: 		return nil, err
370: 	}
371: 
372: 	// we do not want to modify the query,
373: 	// so we create a copy without
374: 	// the timeRange attribute
375: 	d := make(map[string]any)
376: 
377: 	// without the `timeRange` attribute
378: 	for k, v := range qMap {
379: 		if k != timeRangeKey {
380: 			d[k] = v
381: 		}
382: 	}
383: 
384: 	return simplejson.NewFromAny(d).MarshalJSON()
385: }
