142: 					if ok && o.Responses != nil {
143: 						for refId, response := range o.Responses {
144: 							if response.ErrorSource == backend.ErrorSourceDownstream {
145: 								*statusCode = http.StatusBadRequest //force this to be a 400 since it's downstream
146: 								span.SetStatus(codes.Error, strconv.Itoa(*statusCode))
147: 								span.SetAttributes(attribute.String("error.source", "downstream"))
148: 								break
149: 							} else if response.Error != nil {
150: 								connectLogger.Debug("500 error without downstream error source", "error", response.Error, "errorSource", response.ErrorSource, "refId", refId)
151: 								span.SetStatus(codes.Error, "500 error without downstream error source")
152: 							} else {
153: 								span.SetStatus(codes.Error, "500 error without downstream error source and no Error message")
154: 								span.SetAttributes(attribute.String("error.ref_id", refId))
155: 							}
156: 						}
157: 					}
158: 				}
159: 				connectLogger.Debug("responder sending status code", "statusCode", statusCode, "caller", getCaller(ctx))
160: 				b.reportStatus(ctx, *statusCode)
161: 			},
162: 
163: 			func(err error) {
164: 				connectLogger.Error("error caught in handler", "err", err, "caller", getCaller(ctx))
165: 				span.SetStatus(codes.Error, "query error")
166: 
167: 				if err == nil {
168: 					return
169: 				}
170: 
171: 				span.RecordError(err)
172: 
173: 				statusCode := 0
174: 				var k8sErr *errorsK8s.StatusError
175: 				if errors.As(err, &k8sErr) {
176: 					statusCode = int(k8sErr.Status().Code)
177: 				} else {
178: 					// we do not know what kind of error it is,
179: 					// we do not know what status code will get assigned to it,
180: 					// so we use the zero to indicate the unknown.
181: 					connectLogger.Debug("Connect: unknown error returned", "error", err)
182: 				}
183: 				b.reportStatus(ctx, statusCode)
184: 			})
185: 
186: 		raw := &query.QueryDataRequest{}
187: 		err := web.Bind(httpreq, raw)
188: 		if err != nil {
189: 			connectLogger.Error("Hit unexpected error when reading query", "err", err)
190: 			err = errorsK8s.NewBadRequest("error reading query")
191: 			// TODO: can we wrap the error so details are not lost?!
192: 			// errutil.BadRequest(
193: 			// 	"query.bind",
194: 			// 	errutil.WithPublicMessage("Error reading query")).
195: 			// 	Errorf("error reading: %w", err)
196: 			responder.Error(err)
197: 			return
198: 		}
199: 
200: 		qdr, err := handleQuery(ctx, *raw, *b, httpreq, *responder, connectLogger)
201: 
202: 		if err != nil {
203: 			connectLogger.Error("execute error", "http code", query.GetResponseCode(qdr), "err", err)
204: 			logEmptyRefids(raw.Queries, connectLogger)
205: 			if qdr != nil { // if we have a response, we assume the err is set in the response
206: 				responder.Object(query.GetResponseCode(qdr), &query.QueryDataResponse{
207: 					QueryDataResponse: *qdr,
208: 				})
209: 				return
210: 			} else {
211: 				var errorDataResponse backend.DataResponse
212: 
213: 				badRequestErrors := []error{
214: 					service.ErrInvalidDatasourceID,
215: 					service.ErrNoQueriesFound,
216: 					service.ErrMissingDataSourceInfo,
217: 					service.ErrQueryParamMismatch,
218: 					service.ErrDuplicateRefId,
219: 					datasources.ErrDataSourceNotFound,
220: 				}
221: 				isTypedBadRequestError := false
222: 				for _, badRequestError := range badRequestErrors {
223: 					if errors.Is(err, badRequestError) {
224: 						isTypedBadRequestError = true
225: 					}
226: 				}
227: 				if isTypedBadRequestError {
228: 					errorDataResponse = backend.ErrDataResponseWithSource(backend.StatusBadRequest, backend.ErrorSourceDownstream, err.Error())
229: 				} else if strings.Contains(err.Error(), "expression request error") {
230: 					connectLogger.Error("Error calling TransformData in an expression", "err", err)
231: 					errorDataResponse = backend.ErrDataResponseWithSource(backend.StatusBadRequest, backend.ErrorSourceDownstream, err.Error())
232: 				} else {
233: 					connectLogger.Error("unknown error, treated as a 500", "err", err)
234: 					responder.Error(err)
235: 					return
236: 				}
237: 				// TODO ensure errors also return the refId wherever possible
238: 				errorRefId := raw.Queries[0].RefID
239: 				if errorRefId == "" {
240: 					errorRefId = "A"
241: 				}
242: 
243: 				qdr = &backend.QueryDataResponse{
244: 					Responses: map[string]backend.DataResponse{
245: 						errorRefId: errorDataResponse,
246: 					},
247: 				}
248: 				responder.Object(query.GetResponseCode(qdr), &query.QueryDataResponse{
249: 					QueryDataResponse: *qdr,
250: 				})
