58: func (r *subQueryREST) Connect(ctx context.Context, name string, opts runtime.Object, responder rest.Responder) (http.Handler, error) {
59: 	pluginCtx, err := r.builder.getPluginContext(ctx, name)
60: 
61: 	if err != nil {
62: 		if errors.Is(err, datasources.ErrDataSourceNotFound) {
63: 			return nil, r.builder.datasourceResourceInfo.NewNotFound(name)
64: 		}
65: 		return nil, err
66: 	}
67: 
68: 	return http.HandlerFunc(func(w http.ResponseWriter, req *http.Request) {
69: 		dqr := data.QueryDataRequest{}
70: 		err := web.Bind(req, &dqr)
71: 		if err != nil {
72: 			responder.Error(err)
73: 			return
74: 		}
75: 
76: 		queries, dsRef, err := data.ToDataSourceQueries(dqr)
77: 		if err != nil {
78: 			responder.Error(err)
79: 			return
80: 		}
81: 		if dsRef != nil && dsRef.UID != name {
82: 			responder.Error(fmt.Errorf("expected query body datasource and request to match"))
83: 			return
84: 		}
85: 
86: 		ctx = backend.WithGrafanaConfig(ctx, pluginCtx.GrafanaConfig)
87: 		ctx = contextualMiddlewares(ctx)
88: 
89: 		rsp, err := r.builder.client.QueryData(ctx, &backend.QueryDataRequest{
90: 			Queries:       queries,
91: 			PluginContext: pluginCtx,
92: 			Headers:       map[string]string{},
93: 		})
94: 
95: 		// all errors get converted into k8 errors when sent in responder.Error and lose important context like downstream info
96: 		var e errutil.Error
97: 		if errors.As(err, &e) && e.Source == errutil.SourceDownstream {
98: 			responder.Object(int(backend.StatusBadRequest),
99: 				&dsV0.QueryDataResponse{QueryDataResponse: backend.QueryDataResponse{Responses: map[string]backend.DataResponse{
100: 					"A": {
101: 						Error:       errors.New(e.LogMessage),
102: 						ErrorSource: backend.ErrorSourceDownstream,
103: 						Status:      backend.StatusBadRequest,
104: 					},
105: 				}}},
106: 			)
107: 			return
108: 		}
109: 
110: 		if err != nil {
111: 			responder.Error(err)
112: 			return
113: 		}
114: 		responder.Object(dsV0.GetResponseCode(rsp),
115: 			&dsV0.QueryDataResponse{QueryDataResponse: *rsp},
116: 		)
117: 	}), nil
118: }
